4381             // at the moment.
4382             if (Ext0 && Ext1 &&
4383                 (Ext0->getOpcode() != Ext1->getOpcode() ||
4384                  Ext0->getOpcode() == Instruction::CastOps::FPExt))
4385               return false;
4386 
4387             bool IsZExt =
4388                 !Ext0 || Ext0->getOpcode() == Instruction::CastOps::ZExt;
4389             auto *SrcVecTy = cast<VectorType>(toVectorTy(SrcTy, VF));
4390             MulAccCost = Ctx.TTI.getMulAccReductionCost(IsZExt, Opcode, RedTy,
4391                                                         SrcVecTy, CostKind);
