4395           InstructionCost RedCost = Red->computeCost(VF, Ctx);
4396           InstructionCost ExtCost = 0;
4397           if (Ext0)
4398             ExtCost += Ext0->computeCost(VF, Ctx);
4399           if (Ext1)
4400             ExtCost += Ext1->computeCost(VF, Ctx);
4401           if (OuterExt)
4402             ExtCost += OuterExt->computeCost(VF, Ctx);
