4404           return MulAccCost.isValid() &&
4405                  MulAccCost < ExtCost + MulCost + RedCost;
4406         },
4407         Range);
4408   };
4409 
4410   VPValue *VecOp = Red->getVecOp();
4411   VPRecipeBase *Sub = nullptr;
4412   VPValue *A, *B;
4413   VPValue *Tmp = nullptr;
4414 
4415   // Try to match reduce.fadd(fmul(fpext(...), fpext(...))).
4416   if (match(VecOp, m_FMul(m_FPExt(m_VPValue()), m_FPExt(m_VPValue())))) {
