4422       return nullptr;
4423 
4424     auto *RecipeA = dyn_cast<VPWidenCastRecipe>(FMul->getOperand(0));
4425     auto *RecipeB = dyn_cast<VPWidenCastRecipe>(FMul->getOperand(1));
