4441   // If ValB is a constant and can be safely extended, truncate it to the same
4442   // type as ExtA's operand, then extend it to the same type as ExtA. This
4443   // creates two uniform extends that can more easily be matched by the rest of
4444   // the bundling code. The ExtB reference, ValB and operand 1 of Mul are all
4445   // replaced with the new extend of the constant.
4446   auto ExtendAndReplaceConstantOp = [&Ctx](VPWidenCastRecipe *ExtA,
4447                                            VPWidenCastRecipe *&ExtB,
4448                                            VPValue *&ValB, VPWidenRecipe *Mul) {
4449     if (!ExtA || ExtB || !isa<VPIRValue>(ValB))
4450       return;
4451     Type *NarrowTy = Ctx.Types.inferScalarType(ExtA->getOperand(0));
4452     Instruction::CastOps ExtOpc = ExtA->getOpcode();
4453     const APInt *Const;
4454     if (!match(ValB, m_APInt(Const)) ||
4455         !llvm::canConstantBeExtended(
4456             Const, NarrowTy, TTI::getPartialReductionExtendKind(ExtOpc)))
4457       return;
4458     // The truncate ensures that the type of each extended operand is the
4459     // same, and it's been proven that the constant can be extended from
4460     // NarrowTy safely. Necessary since ExtA's extended operand would be
4461     // e.g. an i8, while the const will likely be an i32. This will be
4462     // elided by later optimisations.
4463     VPBuilder Builder(Mul);
4464     auto *Trunc =
4465         Builder.createWidenCast(Instruction::CastOps::Trunc, ValB, NarrowTy);
4466     Type *WideTy = Ctx.Types.inferScalarType(ExtA);
4467     ValB = ExtB = Builder.createWidenCast(ExtOpc, Trunc, WideTy);
4468     Mul->setOperand(1, ExtB);
4469   };
4470 
4471   // Try to match reduce.add(mul(...)).
4472   if (match(VecOp, m_Mul(m_VPValue(A), m_VPValue(B)))) {
4473     auto *RecipeA = dyn_cast_if_present<VPWidenCastRecipe>(A);
4474     auto *RecipeB = dyn_cast_if_present<VPWidenCastRecipe>(B);
4475     auto *Mul = cast<VPWidenRecipe>(VecOp);
4476 
4477     // Convert reduce.add(mul(ext, const)) to reduce.add(mul(ext, ext(const)))
4478     ExtendAndReplaceConstantOp(RecipeA, RecipeB, B, Mul);
4479 
4480     // Match reduce.add/sub(mul(ext, ext)).
4481     if (RecipeA && RecipeB && match(RecipeA, m_ZExtOrSExt(m_VPValue())) &&
4482         match(RecipeB, m_ZExtOrSExt(m_VPValue())) &&
4483         IsMulAccValidAndClampRange(Mul, RecipeA, RecipeB, nullptr)) {
4484       if (Sub)
4485         return new VPExpressionRecipe(RecipeA, RecipeB, Mul,
4486                                       cast<VPWidenRecipe>(Sub), Red);
4487       return new VPExpressionRecipe(RecipeA, RecipeB, Mul, Red);
4488     }
4489     // TODO: Add an expression type for this variant with a negated mul
4490     if (!Sub && IsMulAccValidAndClampRange(Mul, nullptr, nullptr, nullptr))
4491       return new VPExpressionRecipe(Mul, Red);
4492   }
4493   // TODO: Add an expression type for negated versions of other expression
4494   // variants.
4495   if (Sub)
4496     return nullptr;
4497 
4498   // Match reduce.add(ext(mul(A, B))).
4499   if (match(VecOp, m_ZExtOrSExt(m_Mul(m_VPValue(A), m_VPValue(B))))) {
4500     auto *Ext = cast<VPWidenCastRecipe>(VecOp);
4501     auto *Mul = cast<VPWidenRecipe>(Ext->getOperand(0));
4502     auto *Ext0 = dyn_cast_if_present<VPWidenCastRecipe>(A);
4503     auto *Ext1 = dyn_cast_if_present<VPWidenCastRecipe>(B);
4504 
4505     // reduce.add(ext(mul(ext, const)))
4506     // -> reduce.add(ext(mul(ext, ext(const))))
4507     ExtendAndReplaceConstantOp(Ext0, Ext1, B, Mul);
4508 
4509     // reduce.add(ext(mul(ext(A), ext(B))))
4510     // -> reduce.add(mul(wider_ext(A), wider_ext(B)))
4511     // The inner extends must either have the same opcode as the outer extend or
4512     // be the same, in which case the multiply can never result in a negative
4513     // value and the outer extend can be folded away by doing wider
4514     // extends for the operands of the mul.
4515     if (Ext0 && Ext1 &&
4516         (Ext->getOpcode() == Ext0->getOpcode() || Ext0 == Ext1) &&
4517         Ext0->getOpcode() == Ext1->getOpcode() &&
4518         IsMulAccValidAndClampRange(Mul, Ext0, Ext1, Ext) && Mul->hasOneUse()) {
4519       auto *NewExt0 = new VPWidenCastRecipe(
4520           Ext0->getOpcode(), Ext0->getOperand(0), Ext->getResultType(), nullptr,
4521           *Ext0, *Ext0, Ext0->getDebugLoc());
4522       NewExt0->insertBefore(Ext0);
4523 
4524       VPWidenCastRecipe *NewExt1 = NewExt0;
4525       if (Ext0 != Ext1) {
4526         NewExt1 = new VPWidenCastRecipe(Ext1->getOpcode(), Ext1->getOperand(0),
4527                                         Ext->getResultType(), nullptr, *Ext1,
4528                                         *Ext1, Ext1->getDebugLoc());
4529         NewExt1->insertBefore(Ext1);
4530       }
4531       Mul->setOperand(0, NewExt0);
4532       Mul->setOperand(1, NewExt1);
4533       Red->setOperand(1, Mul);
4534       return new VPExpressionRecipe(NewExt0, NewExt1, Mul, Red);
4535     }
4536   }
4537   return nullptr;
4538 }
