1000     if (const auto *R = dyn_cast<VPReplicateRecipe>(V))
1001       if (R->getOpcode() == Instruction::Call) {
1002         // The mask is always the last operand if predicated.
1003         return MatchCalleeIntrinsic(
1004             R->getOperand(R->getNumOperands() - 1 - R->isPredicated()));
1005       }
1006     if (const auto *R = dyn_cast<VPInstruction>(V))
1007       if (R->getOpcode() == Instruction::Call)
1008         return MatchCalleeIntrinsic(R->getOperand(R->getNumOperands() - 1));
