1013 /// Intrinsic matches are combinations of ID matchers, and argument
1014 /// matchers. Higher arity matcher are defined recursively in terms of and-ing
1015 /// them with lower arity matchers. Here's some convenient typedefs for up to
1016 /// several arguments, and more can be added as needed
1017 template <typename T0 = void, typename T1 = void, typename T2 = void,
1018           typename T3 = void>
1019 struct m_Intrinsic_Ty;
1020 template <typename T0> struct m_Intrinsic_Ty<T0> {
1021   using Ty = match_combine_and<IntrinsicID_match, Argument_match<T0>>;
1022 };
1023 template <typename T0, typename T1> struct m_Intrinsic_Ty<T0, T1> {
1024   using Ty =
1025       match_combine_and<typename m_Intrinsic_Ty<T0>::Ty, Argument_match<T1>>;
1026 };
1027 template <typename T0, typename T1, typename T2>
1028 struct m_Intrinsic_Ty<T0, T1, T2> {
1029   using Ty = match_combine_and<typename m_Intrinsic_Ty<T0, T1>::Ty,
1030                                Argument_match<T2>>;
1031 };
1032 template <typename T0, typename T1, typename T2, typename T3>
1033 struct m_Intrinsic_Ty {
1034   using Ty = match_combine_and<typename m_Intrinsic_Ty<T0, T1, T2>::Ty,
1035                                Argument_match<T3>>;
1036 };
