4064 void VPlanTransforms::handleUncountableEarlyExits(VPlan &Plan,
4065                                                   VPBasicBlock *HeaderVPBB,
4066                                                   VPBasicBlock *LatchVPBB,
4067                                                   VPBasicBlock *MiddleVPBB,
4068                                                   EarlyExitStyleTy Style) {
4069   struct EarlyExitInfo {
4070     VPBasicBlock *EarlyExitingVPBB;
4071     VPIRBasicBlock *EarlyExitVPBB;
4072     VPValue *CondToExit;
4073   };
4074 
4075   VPDominatorTree VPDT(Plan);
4076   VPBuilder Builder(LatchVPBB->getTerminator());
4077   SmallVector<EarlyExitInfo> Exits;
4078   for (VPIRBasicBlock *ExitBlock : Plan.getExitBlocks()) {
4079     for (VPBlockBase *Pred : to_vector(ExitBlock->getPredecessors())) {
4080       if (Pred == MiddleVPBB)
4081         continue;
4082       // Collect condition for this early exit.
4083       auto *EarlyExitingVPBB = cast<VPBasicBlock>(Pred);
4084       VPBlockBase *TrueSucc = EarlyExitingVPBB->getSuccessors()[0];
4085       VPValue *CondOfEarlyExitingVPBB;
4086       [[maybe_unused]] bool Matched =
4087           match(EarlyExitingVPBB->getTerminator(),
4088                 m_BranchOnCond(m_VPValue(CondOfEarlyExitingVPBB)));
4089       assert(Matched && "Terminator must be BranchOnCond");
4090 
4091       // Insert the MaskedCond in the EarlyExitingVPBB so the predicator adds
4092       // the correct block mask.
4093       VPBuilder EarlyExitingBuilder(EarlyExitingVPBB->getTerminator());
4094       auto *CondToEarlyExit = EarlyExitingBuilder.createNaryOp(
4095           VPInstruction::MaskedCond,
4096           TrueSucc == ExitBlock
4097               ? CondOfEarlyExitingVPBB
4098               : EarlyExitingBuilder.createNot(CondOfEarlyExitingVPBB));
4099       assert((isa<VPIRValue>(CondOfEarlyExitingVPBB) ||
4100               !VPDT.properlyDominates(EarlyExitingVPBB, LatchVPBB) ||
4101               VPDT.properlyDominates(
4102                   CondOfEarlyExitingVPBB->getDefiningRecipe()->getParent(),
4103                   LatchVPBB)) &&
4104              "exit condition must dominate the latch");
4105       Exits.push_back({
4106           EarlyExitingVPBB,
4107           ExitBlock,
4108           CondToEarlyExit,
4109       });
4110     }
4111   }
4112 
4113   assert(!Exits.empty() && "must have at least one early exit");
4114   // Sort exits by dominance to get the correct program order.
4115   llvm::sort(Exits, [&VPDT](const EarlyExitInfo &A, const EarlyExitInfo &B) {
4116     return VPDT.properlyDominates(A.EarlyExitingVPBB, B.EarlyExitingVPBB);
4117   });
4118 
4119   // Build the AnyOf condition for the latch terminator using logical OR
4120   // to avoid poison propagation from later exit conditions when an earlier
4121   // exit is taken.
4122   VPValue *Combined = Exits[0].CondToExit;
4123   for (const EarlyExitInfo &Info : drop_begin(Exits))
4124     Combined = Builder.createLogicalOr(Combined, Info.CondToExit);
4125 
4126   VPValue *IsAnyExitTaken =
4127       Builder.createNaryOp(VPInstruction::AnyOf, {Combined});
4128 
4129   assert(Style == EarlyExitStyleTy::ReadOnlyUncountableExitsInVectorLoop &&
4130          "Early exit store masking not implemented");
4131 
