4281   VPValue *VecOp = Red->getVecOp();
4282 
4283   // Clamp the range if using extended-reduction is profitable.
4284   auto IsExtendedRedValidAndClampRange =
4285       [&](unsigned Opcode, Instruction::CastOps ExtOpc, Type *SrcTy) -> bool {
4286     return LoopVectorizationPlanner::getDecisionAndClampRange(
4287         [&](ElementCount VF) {
4288           auto *SrcVecTy = cast<VectorType>(toVectorTy(SrcTy, VF));
4289           TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
4290 
4291           InstructionCost ExtRedCost = InstructionCost::getInvalid();
4292           InstructionCost ExtCost =
4293               cast<VPWidenCastRecipe>(VecOp)->computeCost(VF, Ctx);
4294           InstructionCost RedCost = Red->computeCost(VF, Ctx);
4295 
4296           if (Red->isPartialReduction()) {
4297             TargetTransformInfo::PartialReductionExtendKind ExtKind =
4298                 TargetTransformInfo::getPartialReductionExtendKind(ExtOpc);
