4308             // TTI::getExtendedReductionCost only supports integer types.
4309             ExtRedCost = Ctx.TTI.getExtendedReductionCost(
4310                 Opcode, ExtOpc == Instruction::CastOps::ZExt, RedTy, SrcVecTy,
4311                 Red->getFastMathFlags(), CostKind);
4312           }
4313           return ExtRedCost.isValid() && ExtRedCost < ExtCost + RedCost;
4314         },
4315         Range);
