4219   //   EMIT vp<%combined> = logical-or vp<%cond.0>, vp<%cond.1>, vp<%cond.2>
4220   //   ...
4221   //
4222   // vector.early.exit.check:
4223   //   EMIT vp<%first.lane> = first-active-lane vp<%combined>
4224   //   EMIT vp<%at.cond.0> = extract-lane vp<%first.lane>, vp<%cond.0>
4225   //   EMIT branch-on-cond vp<%at.cond.0>
4226   // Successor(s): vector.early.exit.0, vector.early.exit.check.0
4227   //
4228   // vector.early.exit.check.0:
4229   //   EMIT vp<%at.cond.1> = extract-lane vp<%first.lane>, vp<%cond.1>
4230   //   EMIT branch-on-cond vp<%at.cond.1>
4231   // Successor(s): vector.early.exit.1, vector.early.exit.2
4232   VPBasicBlock *CurrentBB = DispatchVPBB;
