4260       Builder.createICmp(CmpInst::ICMP_EQ, LatchExitingBranch->getOperand(0),
4261                          LatchExitingBranch->getOperand(1));
4262 
4263   DebugLoc LatchDL = LatchExitingBranch->getDebugLoc();
4264   LatchExitingBranch->eraseFromParent();
4265   Builder.setInsertPoint(LatchVPBB);
4266   Builder.createNaryOp(VPInstruction::BranchOnTwoConds,
4267                        {IsAnyExitTaken, IsLatchExitTaken}, LatchDL);
