4267                        {IsAnyExitTaken, IsLatchExitTaken}, LatchDL);
4268   LatchVPBB->clearSuccessors();
4269   LatchVPBB->setSuccessors({DispatchVPBB, MiddleVPBB, HeaderVPBB});
4270   DispatchVPBB->setPredecessors({LatchVPBB});
